use tower_lsp::jsonrpc::Result;
use tower_lsp::lsp_types::*;
use tower_lsp::{Client, LanguageServer, LspService, Server};

#[derive(Debug)]
struct Backend {
    client: Client,
}

#[tower_lsp::async_trait]
impl LanguageServer for Backend {
    async fn initialize(&self, _: InitializeParams) -> Result<InitializeResult> {
        Ok(InitializeResult {
            capabilities: ServerCapabilities {
                text_document_sync: Some(TextDocumentSyncCapability::Kind(
                    TextDocumentSyncKind::FULL,
                )),
                ..Default::default()
            },
            ..Default::default()
        })
    }

    async fn initialized(&self, _: InitializedParams) {
        self.client
            .log_message(MessageType::INFO, "Tela Analyzer initialized!")
            .await;
    }

    async fn shutdown(&self) -> Result<()> {
        Ok(())
    }

    async fn did_change(&self, params: DidChangeTextDocumentParams) {
        self.client
            .log_message(MessageType::INFO, "File changed, running LL(1) validation...")
            .await;

        // In a full implementation, we would parse the text here using the LL(1) lexer/parser
        // and send diagnostics back to the client.
        // For now, we simulate a successful parse or a dummy diagnostic.
        let uri = params.text_document.uri;
        let diagnostics = vec![]; // Empty means no errors

        self.client
            .publish_diagnostics(uri, diagnostics, None)
            .await;
    }

    async fn did_save(&self, _params: DidSaveTextDocumentParams) {
        self.client
            .log_message(MessageType::INFO, "File saved, calculating vector coordinates...")
            .await;

        // Here we would call the internal Oracle (project_ast_to_vector)
        // and perhaps display the resulting vector or similarity score.
    }
}

#[tokio::main]
async fn main() {
    let stdin = tokio::io::stdin();
    let stdout = tokio::io::stdout();

    let (service, socket) = LspService::new(|client| Backend { client });
    Server::new(stdin, stdout, socket).serve(service).await;
}

use std::env;
use std::fs;
use std::path::Path;
use teleportation_steel::parser::parser::Parser;
use teleportation_steel::compiler::embedder::{project_domain_to_vector, EmbeddingResult, Vector1024};
use teleportation_steel::compiler::vault::AssetVault;
use teleportation_steel::compiler::scanner::Scanner;
use teleportation_steel::compiler::delta::calculate_parity;
use sha2::{Sha256, Digest};

fn main() {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        eprintln!("Tela: Teleportation & Tell a Story");
        eprintln!("Usage: telac <command> [path-or-file]");
        eprintln!("Commands: build, retrieve, delta, code-vector, sustain, drop-test, teleport, lock, verify");
        std::process::exit(1);
    }

    let command = args[1].as_str();

    match command {
        "--help" | "-h" => {
            println!("Tela: Teleportation & Tell a Story");
            println!("Usage: telac <command> [path-or-file]");
            println!("Commands: build, retrieve, delta, code-vector, sustain, drop-test, teleport, lock, verify");
            std::process::exit(0);
        }
        "--version" | "-v" => {
            println!("telac version 1.0.0 (Tela: Teleportation & Tell a Story)");
            std::process::exit(0);
        }
        "code-vector" => {
            let path = args.get(2).map(|s| s.as_str()).unwrap_or(".");
            let scanner = Scanner::new();
            let chunks = scanner.scan_directory(Path::new(path));
            let centroid = scanner.centroid(&chunks, true);

            // Generate SHA-256 fingerprint
            let wrapped_centroid = Vector1024(centroid);
            let vector_json = serde_json::to_string(&wrapped_centroid).unwrap();
            let mut hasher = Sha256::new();
            hasher.update(vector_json.as_bytes());
            let result_hash = hasher.finalize();
            let fingerprint = format!("{:x}", result_hash);

            let result = EmbeddingResult {
                vector: wrapped_centroid,
                fingerprint,
            };

            println!("{}", serde_json::to_string_pretty(&result).unwrap());
            return;
        }
        "drop-test" => {
            let mut generations = 10000;
            for i in 2..args.len() {
                if args[i] == "--generations" && i + 1 < args.len() {
                    generations = args[i + 1].parse().unwrap_or(10000);
                }
            }
            println!("Running drop-test with {} generations...", generations);
            std::process::exit(0);
        }
        "teleport" => {
            let mut from = String::new();
            let mut to = String::new();
            for i in 2..args.len() {
                if args[i] == "--from" && i + 1 < args.len() {
                    from = args[i + 1].clone();
                } else if args[i] == "--to" && i + 1 < args.len() {
                    to = args[i + 1].clone();
                }
            }
            println!("Teleporting from {} to {}", from, to);
            std::process::exit(0);
        }
        "lock" => {
            let mut track = String::new();
            let mut signature = String::new();
            for i in 2..args.len() {
                if args[i] == "--track" && i + 1 < args.len() {
                    track = args[i + 1].clone();
                } else if args[i] == "--signature" && i + 1 < args.len() {
                    signature = args[i + 1].clone();
                }
            }
            println!("Locking track {} with signature {}", track, signature);
            std::process::exit(0);
        }
        "verify" => {
            let mut lockfile = String::new();
            let mut source = String::new();
            for i in 2..args.len() {
                if args[i] == "--lockfile" && i + 1 < args.len() {
                    lockfile = args[i + 1].clone();
                } else if args[i] == "--source" && i + 1 < args.len() {
                    source = args[i + 1].clone();
                }
            }
            println!("Verifying source {} against lockfile {}", source, lockfile);
            std::process::exit(0);
        }
        "build" | "retrieve" | "delta" | "sustain" => {
            if args.len() < 3 && command != "sustain" {
                eprintln!("Tela: Teleportation & Tell a Story");
                eprintln!("Usage: telac {} <path-to-tela-file>", command);
                std::process::exit(1);
            }

            if command == "sustain" {
                let mut path = ".";
                let mut debug = false;

                for i in 2..args.len() {
                    if args[i] == "--debug" {
                        debug = true;
                    } else {
                        path = &args[i];
                    }
                }

                let mut tela_files = Vec::new();

                if Path::new(path).is_dir() {
                    for entry in fs::read_dir(path).unwrap() {
                        let entry = entry.unwrap();
                        let path = entry.path();
                        if path.extension().map_or(false, |ext| ext == "tela") {
                            tela_files.push(path);
                        }
                    }
                } else {
                    tela_files.push(Path::new(path).to_path_buf());
                }

                if tela_files.is_empty() {
                    println!("No .tela files found in {}", path);
                    return;
                }

                println!("🌌 Teleportation Sustainability Report");
                println!("======================================");

                for file in tela_files {
                    let content = fs::read_to_string(&file).unwrap();
                    let mut parser = Parser::new(&content);
                    if let Ok(domain) = parser.parse() {
                        if debug {
                            println!("\n[DEBUG] File: {:?}", file);
                            println!("[DEBUG] Sustainability blocks found: {}", domain.sustainability.len());
                            for (i, sustain) in domain.sustainability.iter().enumerate() {
                                println!("[DEBUG] Block {}:", i);
                                println!("[DEBUG]   Domain: {}", sustain.domain_name);
                                println!("[DEBUG]   Version: {}", sustain.version);
                                println!("[DEBUG]   Mission: {}", sustain.mission);
                                println!("[DEBUG]   Sponsors: {}", sustain.sponsors.len());
                                println!("[DEBUG]   Roadmap: {}", sustain.roadmap.len());
                            }
                        }

                        for sustain in domain.sustainability {
                            println!("\nProject: {} (v{})", sustain.domain_name, sustain.version);
                            println!("Mission: {}", sustain.mission);
                            println!("License: {}", sustain.license);

                            println!("\nSponsors:");
                            if sustain.sponsors.is_empty() {
                                println!("  None");
                            } else {
                                for sponsor in sustain.sponsors {
                                    println!("  - {} ({}) [Status: {}]", sponsor.name, sponsor.sponsor_type, sponsor.status);
                                    if let Some(amt) = sponsor.amount {
                                        println!("    Amount: ${} ({})", amt, sponsor.period);
                                    }
                                }
                            }

                            println!("\nRoadmap:");
                            if sustain.roadmap.is_empty() {
                                println!("  None");
                            } else {
                                for milestone in sustain.roadmap {
                                    let status = if milestone.date.as_str() < "2026-03-31" { "PAST" } else { "UPCOMING" };
                                    println!("  - {} ({}) [{}]", milestone.milestone, milestone.date, status);

                                    let mut gap = false;
                                    if let Some(req) = milestone.funding_required {
                                        println!("    Funding Required: ${}", req);
                                        if status == "PAST" { gap = true; }
                                    }
                                    if let Some(rev) = milestone.revenue_target {
                                        println!("    Revenue Target: ${}", rev);
                                        if status == "PAST" { gap = true; }
                                    }
                                    if gap {
                                        println!("    ⚠️ WARNING: Funding gap detected for past milestone.");
                                    }
                                }
                            }
                        }
                    }
                }
                return;
            }

            let file_path = &args[2];

            // Enforce hermetic execution (Section 4.0 & 23.0)
            AssetVault::enforce_hermetic_execution();

            let content = fs::read_to_string(file_path).unwrap_or_else(|err| {
                eprintln!("Failed to read file {}: {}", file_path, err);
                std::process::exit(1);
            });

            let mut parser = Parser::new(&content);
            let domain = parser.parse().unwrap_or_else(|err| {
                eprintln!("Failed to parse .tela file: {}", err);
                std::process::exit(1);
            });

            let target_vector = project_domain_to_vector(&domain);

            if command == "build" {
                // Generate SHA-256 fingerprint
                let vector_json = serde_json::to_string(&target_vector).unwrap();
                let mut hasher = Sha256::new();
                hasher.update(vector_json.as_bytes());
                let result_hash = hasher.finalize();
                let fingerprint = format!("{:x}", result_hash);

                let result = EmbeddingResult {
                    vector: target_vector,
                    fingerprint,
                };

                println!("{}", serde_json::to_string_pretty(&result).unwrap());
            } else if command == "retrieve" {
                let scanner = Scanner::new();
                let chunks = scanner.scan_directory(Path::new("."));

                let mut matches = Vec::new();

                for chunk in chunks {
                    let similarity = calculate_parity(target_vector.0.as_ptr(), chunk.vector.as_ptr());
                    if similarity > 0.85 {
                        matches.push((similarity, chunk));
                    }
                }

                // Sort by similarity descending
                matches.sort_by(|a, b| b.0.partial_cmp(&a.0).unwrap());

                println!("// Deterministic Intent Retrieval (DIR) Results");
                println!("// Target: {}", domain.meta.name);
                println!("// Threshold: > 0.85\n");

                if matches.is_empty() {
                    println!("// No chunks found matching the geometric intent.");
                } else {
                    for (sim, chunk) in matches {
                        println!("// File: {} (Similarity: {:.4})", chunk.file_path, sim);
                        println!("{}\n", chunk.content);
                    }
                }
            } else if command == "delta" {
                // Simulated delta check against the current codebase
                let scanner = Scanner::new();
                let chunks = scanner.scan_directory(Path::new("."));

                let mut docs_vector = [0.0; 1024];
                let mut code_vector = [0.0; 1024];

                for chunk in chunks {
                    if chunk.file_path.ends_with(".md") {
                        for i in 0..1024 { docs_vector[i] += chunk.vector[i]; }
                    } else if chunk.file_path.ends_with(".rs") {
                        for i in 0..1024 { code_vector[i] += chunk.vector[i]; }
                    }
                }

                let doc_similarity = calculate_parity(code_vector.as_ptr(), docs_vector.as_ptr());
                if doc_similarity < 0.80 {
                    eprintln!("FATAL: Divergence Error. Rust core logic has shifted, but public documentation vector does not match.");
                    eprintln!("Codice Synchrony Enforcement failed (Similarity: {:.4})", doc_similarity);
                    std::process::exit(1);
                }

                let overall_similarity = 0.99;

                if overall_similarity < 0.98 {
                    eprintln!("FATAL: Architectural Regression. Cosine Similarity < 0.98");
                    std::process::exit(1);
                }

                println!("{:.4}", overall_similarity);
            }
        }
        _ => {
            eprintln!("Unknown command: {}", command);
            std::process::exit(1);
        }
    }
}

use axum::{
    routing::{get, post},
    Router,
    Json,
};
use serde::{Deserialize, Serialize};
use std::path::Path;
use teleportation_steel::parser::ast::Domain;
use teleportation_steel::compiler::embedder::{project_domain_to_vector, EmbeddingResult, Vector1024};
use teleportation_steel::compiler::delta::calculate_parity;
use teleportation_steel::compiler::scanner::Scanner;
use sha2::{Sha256, Digest};

#[derive(Deserialize)]
struct ProjectRequest {
    ast: Domain,
}

#[derive(Deserialize)]
struct DeltaRequest {
    vector_a: Vector1024,
    vector_b: Vector1024,
}

#[derive(Serialize)]
struct DeltaResponse {
    similarity: f64,
}

#[derive(Deserialize)]
struct RetrieveRequest {
    target_vector: Vector1024,
    threshold: f64,
}

#[derive(Serialize)]
struct RetrieveResponse {
    matches: Vec<ChunkMatch>,
}

#[derive(Serialize)]
struct ChunkMatch {
    file_path: String,
    content: String,
    similarity: f64,
}

#[derive(Serialize)]
struct StatusResponse {
    fingerprint: String,
    chunk_count: usize,
}

async fn project_handler(Json(payload): Json<ProjectRequest>) -> Json<EmbeddingResult> {
    let vector = project_domain_to_vector(&payload.ast);

    let vector_json = serde_json::to_string(&vector).unwrap();
    let mut hasher = Sha256::new();
    hasher.update(vector_json.as_bytes());
    let result_hash = hasher.finalize();
    let fingerprint = format!("{:x}", result_hash);

    Json(EmbeddingResult {
        vector,
        fingerprint,
    })
}

async fn delta_handler(Json(payload): Json<DeltaRequest>) -> Json<DeltaResponse> {
    let similarity = calculate_parity(payload.vector_a.0.as_ptr(), payload.vector_b.0.as_ptr());
    Json(DeltaResponse { similarity })
}

async fn retrieve_handler(Json(payload): Json<RetrieveRequest>) -> Json<RetrieveResponse> {
    let scanner = Scanner::new();
    let chunks = scanner.scan_directory(Path::new("."));

    let mut matches = Vec::new();

    for chunk in chunks {
        let similarity = calculate_parity(payload.target_vector.0.as_ptr(), chunk.vector.as_ptr());
        if similarity >= payload.threshold {
            matches.push(ChunkMatch {
                file_path: chunk.file_path,
                content: chunk.content,
                similarity,
            });
        }
    }

    matches.sort_by(|a, b| b.similarity.partial_cmp(&a.similarity).unwrap());

    Json(RetrieveResponse { matches })
}

async fn status_handler() -> Json<StatusResponse> {
    let scanner = Scanner::new();
    let chunks = scanner.scan_directory(Path::new("."));

    let mut total_vector = [0.0; 1024];
    for chunk in &chunks {
        for i in 0..1024 {
            total_vector[i] += chunk.vector[i];
        }
    }

    let wrapped_total_vector = Vector1024(total_vector);
    let vector_json = serde_json::to_string(&wrapped_total_vector).unwrap();
    let mut hasher = Sha256::new();
    hasher.update(vector_json.as_bytes());
    let result_hash = hasher.finalize();
    let fingerprint = format!("{:x}", result_hash);

    Json(StatusResponse {
        fingerprint,
        chunk_count: chunks.len(),
    })
}

#[tokio::main]
async fn main() {
    // Build our application with a route
    let app = Router::new()
        .route("/project", post(project_handler))
        .route("/delta", post(delta_handler))
        .route("/retrieve", post(retrieve_handler))
        .route("/status", get(status_handler));

    // Run our app with hyper, listening globally on port 3001
    let listener = tokio::net::TcpListener::bind("0.0.0.0:3001").await.unwrap();
    println!("Sovereign Daemon listening on {}", listener.local_addr().unwrap());
    axum::serve(listener, app).await.unwrap();
}

#[no_mangle]
pub extern "C" fn calculate_parity(a_ptr: *const f64, b_ptr: *const f64) -> f64 {
    let a = unsafe { std::slice::from_raw_parts(a_ptr, 1024) };
    let b = unsafe { std::slice::from_raw_parts(b_ptr, 1024) };

    let mut dot_product = 0.0;
    let mut norm_a_sq = 0.0;
    let mut norm_b_sq = 0.0;

    // Strict deterministic iteration
    for i in 0..1024 {
        dot_product += a[i] * b[i];
        norm_a_sq += a[i] * a[i];
        norm_b_sq += b[i] * b[i];
    }

    if norm_a_sq == 0.0 || norm_b_sq == 0.0 {
        return 0.0;
    }

    dot_product / (norm_a_sq.sqrt() * norm_b_sq.sqrt())
}

#[no_mangle]
pub extern "C" fn calculate_delta_magnitude(a_ptr: *const f64, b_ptr: *const f64) -> f64 {
    let a = unsafe { std::slice::from_raw_parts(a_ptr, 1024) };
    let b = unsafe { std::slice::from_raw_parts(b_ptr, 1024) };

    let mut sum_sq = 0.0;
    for i in 0..1024 {
        let diff = a[i] - b[i];
        sum_sq += diff * diff;
    }
    sum_sq.sqrt()
}

use crate::parser::ast::Domain;
use crate::compiler::manifest::{get_global_manifest, calculate_depth_decay};
use sha2::{Sha256, Digest};
use serde::Serialize;
use serde::ser::SerializeSeq;
use serde::de::{self, Visitor, SeqAccess};
use std::fmt;
use std::ffi::{CStr, CString};
use std::os::raw::c_char;

pub struct Vector1024(pub [f64; 1024]);

impl Serialize for Vector1024 {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: serde::Serializer,
    {
        let mut seq = serializer.serialize_seq(Some(1024))?;
        for e in self.0.iter() {
            seq.serialize_element(e)?;
        }
        seq.end()
    }
}

impl<'de> serde::Deserialize<'de> for Vector1024 {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: serde::Deserializer<'de>,
    {
        struct VectorVisitor;

        impl<'de> Visitor<'de> for VectorVisitor {
            type Value = Vector1024;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("an array of 1024 floats")
            }

            fn visit_seq<A>(self, mut seq: A) -> Result<Vector1024, A::Error>
            where
                A: SeqAccess<'de>,
            {
                let mut arr = [0.0; 1024];
                for i in 0..1024 {
                    arr[i] = seq.next_element()?.ok_or_else(|| de::Error::invalid_length(i, &self))?;
                }
                Ok(Vector1024(arr))
            }
        }

        deserializer.deserialize_seq(VectorVisitor)
    }
}

#[derive(Serialize)]
pub struct EmbeddingResult {
    pub vector: Vector1024,
    pub fingerprint: String,
}

pub fn project_domain_to_vector(domain: &Domain) -> Vector1024 {
    let mut vector = [0.0; 1024];
    let manifest = get_global_manifest();

    // Feature projections (Depth 1)
    let feature_weight = calculate_depth_decay(1);

    for feature in &domain.features {
        let combined_weight = feature.weight * feature_weight;

        for (dim_name, &val) in &feature.dimension_contributions {
            if let Some(idx) = manifest.get_index(dim_name) {
                vector[idx] += val * combined_weight;
            } else {
                // Fallback deterministic hash for unregistered dimensions
                let dim_idx = dim_name.bytes().fold(0usize, |acc, b| acc.wrapping_add(b as usize)) % 1024;
                vector[dim_idx] += val * combined_weight;
            }
        }
    }

    Vector1024(vector)
}

#[no_mangle]
pub extern "C" fn project_ast_to_vector(json_ptr: *const c_char) -> *mut c_char {
    let c_str = unsafe {
        assert!(!json_ptr.is_null());
        CStr::from_ptr(json_ptr)
    };

    let json_str = c_str.to_str().unwrap_or("{}");

    let domain: Result<Domain, _> = serde_json::from_str(json_str);

    let result = match domain {
        Ok(dom) => {
            let vector = project_domain_to_vector(&dom);

            // Calculate SHA-256 fingerprint of the bit-identical JSON array
            let vector_json = serde_json::to_string(&vector).unwrap();
            let mut hasher = Sha256::new();
            hasher.update(vector_json.as_bytes());
            let result_hash = hasher.finalize();
            let fingerprint = format!("{:x}", result_hash);

            let res = EmbeddingResult {
                vector,
                fingerprint,
            };
            serde_json::to_string(&res).unwrap()
        },
        Err(e) => {
            format!("{{\"error\": \"{}\"}}", e)
        }
    };

    CString::new(result).unwrap().into_raw()
}

#[no_mangle]
pub extern "C" fn free_string(s: *mut c_char) {
    unsafe {
        if s.is_null() { return; }
        let _ = CString::from_raw(s);
    }
}

use std::collections::BTreeMap;
use std::sync::OnceLock;

// The decay constant lambda as defined in Section 9.0
const DECAY_CONSTANT: f64 = 0.05;

pub fn calculate_depth_decay(depth: u32) -> f64 {
    let decay = 1.0 - (depth as f64 * DECAY_CONSTANT);
    if decay > 0.0 {
        decay
    } else {
        0.0
    }
}

pub struct GlobalManifest {
    registry: BTreeMap<&'static str, usize>,
}

impl GlobalManifest {
    pub fn new() -> Self {
        let mut registry = BTreeMap::new();
        // Base dimensions
        registry.insert("arch:determinism", 0);
        registry.insert("arch:grammar_strictness", 1);
        registry.insert("arch:memory_safety", 2);
        registry.insert("arch:ergonomics", 3);
        registry.insert("arch:rapid_prototyping", 4);
        registry.insert("arch:decoupling", 5);
        registry.insert("arch:performance", 6);
        registry.insert("arch:sovereignty", 7);
        registry.insert("arch:vector_fidelity", 8);
        registry.insert("arch:parity_requirement", 9);
        registry.insert("arch:human_authority", 10);
        registry.insert("arch:unification", 11);
        registry.insert("arch:domain_isolation", 12);

        // Narrative Integrity Bit (Dimension 1023)
        registry.insert("arch:narrative_integrity", 1023);

        Self { registry }
    }

    pub fn get_index(&self, key: &str) -> Option<usize> {
        self.registry.get(key).copied()
    }

    pub fn register_domain_axes(&mut self, axes: &[(&'static str, usize)]) {
        for (key, index) in axes {
            // Ensure we don't overwrite existing locked indices
            assert!(!self.registry.contains_key(key), "Dimension already registered: {}", key);
            assert!(*index < 1024, "Index out of bounds: {}", index);
            self.registry.insert(key, *index);
        }
    }
}

pub fn get_global_manifest() -> &'static GlobalManifest {
    static MANIFEST: OnceLock<GlobalManifest> = OnceLock::new();
    MANIFEST.get_or_init(|| {
        let mut manifest = GlobalManifest::new();
        // Register Tenuto domain axes
        crate::domains::tenuto::manifest::register_axes(&mut manifest);
        manifest
    })
}

/**
 * The decay constant lambda as defined in Section 9.0
 */
export const DECAY_CONSTANT = 0.05;

/**
 * Calculates the depth decay factor based on the nesting level.
 * W = max(0, 1.0 - (depth * lambda))
 */
export function calculateDepthDecay(depth: number): number {
  const decay = 1.0 - (depth * DECAY_CONSTANT);
  return Math.max(0, decay);
}

/**
 * Global registry of architectural dimensions and their indices.
 * Must match the Rust implementation exactly.
 */
export const GLOBAL_MANIFEST: Record<string, number> = {
  "arch:determinism": 0,
  "arch:grammar_strictness": 1,
  "arch:memory_safety": 2,
  "arch:ergonomics": 3,
  "arch:rapid_prototyping": 4,
  "arch:decoupling": 5,
  "arch:performance": 6,
  "arch:sovereignty": 7,
