use sha2::{Sha256, Digest};
use std::collections::HashMap;
use std::sync::Mutex;
use std::fs;
use std::path::Path;
use std::env;

static ORACLE_TAPE: Mutex<Option<HashMap<String, String>>> = Mutex::new(None);

/// Track C Sandbox: Manages unpredictable externalities (e.g., volatile APIs)
/// by freezing chaotic JSON payloads into a local, immutable fixture mapped
/// to the rational timeline.
pub struct TrackCSandbox;

impl TrackCSandbox {
    /// Initializes the Oracle Tape based on TELA_TAPE_MODE.
    pub fn init() {
        if let Ok(mode) = env::var("TELA_TAPE_MODE") {
            if mode == "replay" {
                let _ = Self::load_tape(Path::new("oracle_tape.json"));
            }
        }
    }

    /// Computes the SHA-256 deterministic hash of a JSON payload.
    pub fn compute_hash(payload: &str) -> String {
        let mut hasher = Sha256::new();
        hasher.update(payload.as_bytes());
        let result = hasher.finalize();
        hex::encode(result)
    }

    /// Freezes a chaotic JSON payload into the Oracle Tape.
    pub fn freeze_payload(payload: &str) -> String {
        let hash = Self::compute_hash(payload);
        let mut tape_guard = ORACLE_TAPE.lock().unwrap();
        let tape = tape_guard.get_or_insert_with(HashMap::new);
        tape.insert(hash.clone(), payload.to_string());

        if let Ok(mode) = env::var("TELA_TAPE_MODE") {
            if mode == "record" {
                let _ = Self::save_tape(Path::new("oracle_tape.json"));
            }
        }

        hash
    }

    /// Replays a frozen payload from the Oracle Tape using its SHA-256 hash.
    /// Bypasses the network entirely to guarantee bit-identical execution of historical entropy.
    pub fn replay_payload(hash: &str) -> Option<String> {
        if let Ok(mode) = env::var("TELA_TAPE_MODE") {
            if mode == "replay" {
                let tape_guard = ORACLE_TAPE.lock().unwrap();
                if let Some(tape) = tape_guard.as_ref() {
                    return tape.get(hash).cloned();
                }
            }
        }

        let tape_guard = ORACLE_TAPE.lock().unwrap();
        if let Some(tape) = tape_guard.as_ref() {
            tape.get(hash).cloned()
        } else {
            None
        }
    }

    /// Saves the current Oracle Tape to a JSON file.
    pub fn save_tape(path: &Path) -> std::io::Result<()> {
        let tape_guard = ORACLE_TAPE.lock().unwrap();
        if let Some(tape) = tape_guard.as_ref() {
            let json = serde_json::to_string_pretty(tape)?;
            fs::write(path, json)?;
        }
        Ok(())
    }

    /// Loads the Oracle Tape from a JSON file.
    pub fn load_tape(path: &Path) -> std::io::Result<()> {
        if path.exists() {
            let json = fs::read_to_string(path)?;
            let tape: HashMap<String, String> = serde_json::from_str(&json)?;
            let mut tape_guard = ORACLE_TAPE.lock().unwrap();
            *tape_guard = Some(tape);
        }
        Ok(())
    }
}

/// FFI boundary for passing the frozen JSON payload and its SHA-256 deterministic hash.
#[no_mangle]
pub extern "C" fn ffi_track_c_replay(hash_ptr: *const u8, hash_len: usize) -> i32 {
    let hash_bytes = unsafe { std::slice::from_raw_parts(hash_ptr, hash_len) };
    let hash = String::from_utf8_lossy(hash_bytes);
    if TrackCSandbox::replay_payload(&hash).is_some() {
        1
    } else {
        0
    }
}

import * as fs from 'fs';
import * as path from 'path';
import * as crypto from 'crypto';

export class TrackCSandbox {
  private mode: string;
  private tapePath: string;

  constructor() {
    this.mode = process.env.TELA_TAPE_MODE || 'replay';
    // Using process.cwd() ensures we resolve to the project root
    this.tapePath = path.join(process.cwd(), 'fixtures', 'tapes.json');
  }

  private computeHash(payload: any): string {
    const str = JSON.stringify(payload);
    return crypto.createHash('sha256').update(str).digest('hex');
  }

  async freezePayload(key: string, payload: any): Promise<void> {
    if (this.mode !== 'record') {
      return;
    }

    const hash = this.computeHash(payload);
    const fixtureDir = path.dirname(this.tapePath);
    if (!fs.existsSync(fixtureDir)) {
      fs.mkdirSync(fixtureDir, { recursive: true });
    }

    let tapes: Record<string, any> = {};
    if (fs.existsSync(this.tapePath)) {
      tapes = JSON.parse(fs.readFileSync(this.tapePath, 'utf-8'));
    }

    tapes[key] = {
      hash,
      payload
    };

    fs.writeFileSync(this.tapePath, JSON.stringify(tapes, null, 2), 'utf-8');
  }

  async replayPayload(key: string): Promise<any> {
    if (this.mode !== 'replay') {
      throw new Error(`Cannot replay in mode: ${this.mode}`);
    }

    if (!fs.existsSync(this.tapePath)) {
      throw new Error(`Tape file not found at ${this.tapePath}`);
    }

    const tapes = JSON.parse(fs.readFileSync(this.tapePath, 'utf-8'));
    if (!tapes[key]) {
      throw new Error(`No tape found for key: ${key}`);
    }

    const { hash, payload } = tapes[key];
    const currentHash = this.computeHash(payload);

    if (currentHash !== hash) {
      throw new Error(`Hash mismatch for key: ${key}. Expected ${hash}, got ${currentHash}`);
    }

    return payload;
  }
}

use super::weights::calculate_depth_weight;

/// A raw AST node extracted from the host language.
#[derive(Debug, Clone)]
pub struct AstNode {
    pub id: String,
    pub depth: u32,
    pub raw_content: String,
    pub children: Vec<AstNode>,
}

/// A geometrically weighted semantic chunk.
#[derive(Debug, Clone)]
pub struct SemanticChunk {
    pub id: String,
    pub weight: f32,
    pub content: String,
}

/// The Embedding Oracle performs a topological traversal of the AST,
/// extracting fundamental logic blocks and tagging them with predefined,
/// static mathematical weights.
pub struct Oracle {
    pub lambda: f32,
}

impl Oracle {
    pub fn new(lambda: f32) -> Self {
        Self { lambda }
    }

    /// Extracts semantic chunks from the AST using a strict geometric function.
    pub fn extract_chunks(&self, root: &AstNode) -> Vec<SemanticChunk> {
        let mut chunks = Vec::new();
        self.traverse(root, &mut chunks);
        chunks
    }

    fn traverse(&self, node: &AstNode, chunks: &mut Vec<SemanticChunk>) {
        let weight = calculate_depth_weight(node.depth, self.lambda);

        // Only extract chunks with a non-zero geometric weight
        if weight > 0.0 {
            chunks.push(SemanticChunk {
                id: node.id.clone(),
                weight,
                content: node.raw_content.clone(),
            });
        }

        // Topologically traverse children
        for child in &node.children {
            self.traverse(child, chunks);
        }
    }
}

/// Implements the Depth Decay Formula: W = max(0, 1.0 - (d * lambda))
/// Ensures logic nested deeper into the AST geometrically decays in weight
/// to prevent the butterfly effect.
pub fn calculate_depth_weight(depth: u32, lambda: f32) -> f32 {
    let d = depth as f32;
    let decay = d * lambda;
    let weight = 1.0 - decay;

    if weight > 0.0 {
        weight
    } else {
        0.0
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_depth_decay() {
        assert_eq!(calculate_depth_weight(0, 0.1), 1.0);
        assert_eq!(calculate_depth_weight(5, 0.1), 0.5);
        assert_eq!(calculate_depth_weight(10, 0.1), 0.0);
        assert_eq!(calculate_depth_weight(15, 0.1), 0.0); // max(0, ...)
    }
}

use serde::{Deserialize, Serialize}; use std::collections::BTreeMap; // BTreeMap for deterministic serialization order
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)] pub struct Domain { pub name: String, pub version: String, pub meta: MetaBlock, pub features: Vec<FeatureBlock>, pub deterministics: Vec<DeterministicBlock>, #[serde(default)] pub sustainability: Vec<SustainabilityBlock>, }
