use std::iter::Peekable;
use std::str::Chars;

#[derive(Debug, PartialEq, Clone)]
pub enum Token {
    Keyword(String),
    String(String),
    Number(String),
    Ident(String),
    LBrace,
    RBrace,
    LBracket,
    RBracket,
    Colon,
    Comma,
    At,
    Eof,
}

pub struct Lexer<'a> {
    input: Peekable<Chars<'a>>,
    pub line: usize,
    pub column: usize,
}

impl<'a> Lexer<'a> {
    pub fn new(input: &'a str) -> Self {
        Self {
            input: input.chars().peekable(),
            line: 1,
            column: 1,
        }
    }

    fn advance(&mut self) -> Option<char> {
        let c = self.input.next();
        if let Some(ch) = c {
            if ch == '\n' {
                self.line += 1;
                self.column = 1;
            } else {
                self.column += 1;
            }
        }
        c
    }

    fn peek(&mut self) -> Option<&char> {
        self.input.peek()
    }

    fn skip_whitespace_and_comments(&mut self) {
        loop {
            match self.peek() {
                Some(&c) if c.is_whitespace() => {
                    self.advance();
                }
                Some(&'/') => {
                    // Peek ahead without advancing if possible, but Peekable only peeks 1.
                    // We'll just clone the iterator to peek ahead.
                    let mut lookahead = self.input.clone();
                    lookahead.next(); // skip '/'
                    if let Some(&'/') = lookahead.peek() {
                        self.advance(); // consume '/'
                        self.advance(); // consume '/'
                        while let Some(&c) = self.peek() {
                            if c == '\n' {
                                break;
                            }
                            self.advance();
                        }
                    } else {
                        break;
                    }
                }
                Some(&'%') => {
                    let mut lookahead = self.input.clone();
                    lookahead.next(); // skip '%'
                    if let Some(&'%') = lookahead.peek() {
                        self.advance(); // consume '%'
                        self.advance(); // consume '%'
                        while let Some(&c) = self.peek() {
                            if c == '\n' {
                                break;
                            }
                            self.advance();
                        }
                    } else {
                        break;
                    }
                }
                Some(&'#') => {
                    self.advance(); // consume '#'
                    while let Some(&c) = self.peek() {
                        if c == '\n' {
                            break;
                        }
                        self.advance();
                    }
                }
                _ => break,
            }
        }
    }

    pub fn next_token(&mut self) -> Result<Token, String> {
        self.skip_whitespace_and_comments();

        let c = match self.peek() {
            Some(&ch) => ch,
            None => return Ok(Token::Eof),
        };

        match c {
            '{' => {
                self.advance();
                Ok(Token::LBrace)
            }
            '}' => {
                self.advance();
                Ok(Token::RBrace)
            }
            '[' => {
                self.advance();
                Ok(Token::LBracket)
            }
            ']' => {
                self.advance();
                Ok(Token::RBracket)
            }
            ':' => {
                self.advance();
                Ok(Token::Colon)
            }
            ',' => {
                self.advance();
                Ok(Token::Comma)
            }
            '@' => {
                self.advance();
                Ok(Token::At)
            }
            '"' => self.read_string(),
            c if c.is_ascii_digit() || c == '-' || c == '.' => self.read_number(),
            c if c.is_alphabetic() || c == '_' => self.read_ident_or_keyword(),
            _ => {
                let err = format!("Unexpected character '{}' at line {}, col {}", c, self.line, self.column);
                self.advance();
                Err(err)
            }
        }
    }

    pub fn tokenize(&mut self) -> Result<Vec<Token>, String> {
        let mut tokens = Vec::new();
        loop {
            let token = self.next_token()?;
            let is_eof = token == Token::Eof;
            tokens.push(token);
            if is_eof {
                break;
            }
        }
        Ok(tokens)
    }

    fn read_string(&mut self) -> Result<Token, String> {
        self.advance(); // skip opening quote
        let mut is_multiline = false;

        // Check for multiline string """
        if let Some(&'"') = self.peek() {
            self.advance();
            if let Some(&'"') = self.peek() {
                self.advance();
                is_multiline = true;
            } else {
                // Empty string ""
                return Ok(Token::String(String::new()));
            }
        }

        let mut result = String::new();
        if is_multiline {
            let mut quotes_count = 0;
            loop {
                match self.advance() {
                    Some('"') => {
                        quotes_count += 1;
                        if quotes_count == 3 {
                            break;
                        }
                    }
                    Some(c) => {
                        for _ in 0..quotes_count {
                            result.push('"');
                        }
                        quotes_count = 0;
                        result.push(c);
                    }
                    None => return Err(format!("Unterminated multiline string starting at line {}", self.line)),
                }
            }
        } else {
            loop {
                match self.advance() {
                    Some('"') => break,
                    Some('\\') => {
                        match self.advance() {
                            Some('n') => result.push('\n'),
                            Some('r') => result.push('\r'),
                            Some('t') => result.push('\t'),
                            Some('\\') => result.push('\\'),
                            Some('"') => result.push('"'),
                            Some(c) => {
                                result.push('\\');
                                result.push(c);
                            }
                            None => return Err("Unterminated string escape".to_string()),
                        }
                    }
                    Some(c) => result.push(c),
                    None => return Err(format!("Unterminated string starting at line {}", self.line)),
                }
            }
        }

        Ok(Token::String(result))
    }

    fn read_number(&mut self) -> Result<Token, String> {
        let mut result = String::new();
        while let Some(&c) = self.peek() {
            if c.is_ascii_digit() || c == '.' || c == '-' {
                result.push(c);
                self.advance();
            } else {
                break;
            }
        }
        Ok(Token::Number(result))
    }

    fn read_ident_or_keyword(&mut self) -> Result<Token, String> {
        let mut result = String::new();
        while let Some(&c) = self.peek() {
            if c.is_alphanumeric() || c == '_' {
                result.push(c);
                self.advance();
            } else {
                break;
            }
        }

        match result.as_str() {
            "domain" | "meta" | "feature" | "deterministic" | "sustainability" => Ok(Token::Keyword(result)),
            _ => Ok(Token::Ident(result)),
        }
    }
}

export type TokenType =
  | 'HEADING'
  | 'TEXT'
  | 'CODE_BLOCK'
  | 'LIST_ITEM'
  | 'EOF';

export interface Token {
  type: TokenType;
  value: string;
  line: number;
  column: number;
}

export class GrammarViolationError extends Error {
  constructor(message: string, public line: number, public column: number) {
    super(`Grammar Violation at ${line}:${column} - ${message}`);
    this.name = 'GrammarViolationError';
  }
}

export class Lexer {
  private input: string;
  private position: number = 0;
  private line: number = 1;
  private column: number = 1;

  constructor(input: string) {
    this.input = input;
  }

  private advance(): string {
    const char = this.input[this.position];
    this.position++;
    if (char === '\n') {
      this.line++;
      this.column = 1;
    } else {
      this.column++;
    }
    return char;
  }

  private peek(): string | null {
    if (this.position >= this.input.length) return null;
    return this.input[this.position];
  }

  public nextToken(): Token {
    if (this.position >= this.input.length) {
      return { type: 'EOF', value: '', line: this.line, column: this.column };
    }

    // Check for legacy syntax
    if (this.input.substring(this.position).trimStart().startsWith('domain "')) {
      throw new GrammarViolationError('Protocol Violation: Legacy .tela DSL syntax is deprecated.', this.line, this.column);
    }

    const startLine = this.line;
    const startColumn = this.column;
    const char = this.peek()!;

    if (char === '#') {
      let value = '';
      while (this.peek() === '#') {
        value += this.advance();
      }
      if (this.peek() === ' ') {
        this.advance(); // skip space
      }
      let headingText = '';
      while (this.peek() !== null && this.peek() !== '\n') {
        headingText += this.advance();
      }
      return { type: 'HEADING', value: headingText.trim(), line: startLine, column: startColumn };
    }

    if (this.input.substring(this.position).startsWith('```')) {
      this.advance(); this.advance(); this.advance(); // skip ```
      let value = '';
      while (this.peek() !== null && !this.input.substring(this.position).startsWith('```')) {
        value += this.advance();
      }
      if (this.peek() !== null) {
        this.advance(); this.advance(); this.advance(); // skip ```
      }
      return { type: 'CODE_BLOCK', value, line: startLine, column: startColumn };
    }

    if (char === '-' && this.input[this.position + 1] === ' ') {
      this.advance(); this.advance(); // skip "- "
      let value = '';
      while (this.peek() !== null && this.peek() !== '\n') {
        value += this.advance();
      }
      return { type: 'LIST_ITEM', value: value.trim(), line: startLine, column: startColumn };
    }

    // Text
    let value = '';
    while (this.peek() !== null && this.peek() !== '#' && !this.input.substring(this.position).startsWith('```') && !(this.peek() === '-' && this.input[this.position + 1] === ' ')) {
      value += this.advance();
    }

    // If value is just whitespace, skip it and get next token
    if (value.trim() === '') {
      return this.nextToken();
    }

    return { type: 'TEXT', value: value.trim(), line: startLine, column: startColumn };
  }

  public tokenize(): Token[] {
    const tokens: Token[] = [];
    while (true) {
      const token = this.nextToken();
      tokens.push(token);
      if (token.type === 'EOF') break;
    }
    return tokens;
  }
}

pub mod ast;
pub mod lexer;
pub mod parser;

use crate::parser::ast::*;
use crate::parser::lexer::{Lexer, Token};
use std::collections::BTreeMap;

pub struct Parser<'a> {
    lexer: Lexer<'a>,
    current_token: Token,
}

impl<'a> Parser<'a> {
    pub fn new(input: &'a str) -> Self {
        let mut lexer = Lexer::new(input);
        let current_token = lexer.next_token().unwrap_or(Token::Eof);
        Self { lexer, current_token }
    }

    fn advance(&mut self) -> Result<(), String> {
        self.current_token = self.lexer.next_token()?;
        Ok(())
    }

    fn expect(&mut self, expected: Token) -> Result<(), String> {
        if self.current_token == expected {
            self.advance()?;
            Ok(())
        } else {
            Err(format!(
                "Expected {:?}, found {:?} at line {}, col {}",
                expected, self.current_token, self.lexer.line, self.lexer.column
            ))
        }
    }

    fn expect_keyword(&mut self, kw: &str) -> Result<(), String> {
        if let Token::Keyword(ref k) = self.current_token {
            if k == kw {
                self.advance()?;
                return Ok(());
            }
        }
        Err(format!(
            "Expected keyword '{}', found {:?} at line {}, col {}",
            kw, self.current_token, self.lexer.line, self.lexer.column
        ))
    }

    fn parse_string(&mut self) -> Result<String, String> {
        if let Token::String(ref s) = self.current_token {
            let val = s.clone();
            self.advance()?;
            Ok(val)
        } else {
            Err(format!(
                "Expected string, found {:?} at line {}, col {}",
                self.current_token, self.lexer.line, self.lexer.column
            ))
        }
    }

    fn parse_number(&mut self) -> Result<f64, String> {
        if let Token::Number(ref n) = self.current_token {
            let val = n.parse::<f64>().map_err(|_| {
                format!(
                    "Invalid number '{}' at line {}, col {}",
                    n, self.lexer.line, self.lexer.column
                )
            })?;
            self.advance()?;
            Ok(val)
        } else {
            Err(format!(
                "Expected number, found {:?} at line {}, col {}",
                self.current_token, self.lexer.line, self.lexer.column
            ))
        }
    }

    fn parse_ident(&mut self) -> Result<String, String> {
        if let Token::Ident(ref id) = self.current_token {
            let val = id.clone();
            self.advance()?;
            Ok(val)
        } else {
            Err(format!(
                "Expected identifier, found {:?} at line {}, col {}",
                self.current_token, self.lexer.line, self.lexer.column
            ))
        }
    }

    pub fn parse(&mut self) -> Result<Domain, String> {
        let mut domain_opt = None;
        let mut top_level_sustainability = Vec::new();

        while self.current_token != Token::Eof {
            match self.current_token {
                Token::Keyword(ref k) if k == "domain" => {
                    domain_opt = Some(self.parse_domain()?);
                }
                Token::Keyword(ref k) if k == "sustainability" => {
                    top_level_sustainability.push(self.parse_sustainability_block()?);
                }
                _ => {
                    // Skip unknown top-level tokens
                    self.advance()?;
                }
            }
        }

        if let Some(mut domain) = domain_opt {
            domain.sustainability.extend(top_level_sustainability);
            Ok(domain)
        } else if !top_level_sustainability.is_empty() {
            // Return a dummy domain if only sustainability is found
            let first = &top_level_sustainability[0];
            Ok(Domain {
                name: first.domain_name.clone(),
                version: first.version.clone(),
                meta: MetaBlock {
                    name: first.domain_name.clone(),
                    sprint_id: "SUSTAIN-ONLY".to_string(),
                    author: "Architect".to_string(),
                    recipient: "Tela AI".to_string(),
                    baseline_centroid: "".to_string(),
                    target_similarity: 0.0,
                    dimensions: 1024,
                    note: None,
                },
                features: Vec::new(),
                deterministics: Vec::new(),
                sustainability: top_level_sustainability,
            })
        } else {
            Err("No domain or sustainability block found".to_string())
        }
    }

    fn parse_domain(&mut self) -> Result<Domain, String> {
        self.expect_keyword("domain")?;
        let name = self.parse_string()?;
        let version = self.parse_string()?;
        self.expect(Token::LBrace)?;

        let mut meta = None;
        let mut features = Vec::new();
        let mut deterministics = Vec::new();
        let mut sustainability = Vec::new();

        while self.current_token != Token::RBrace && self.current_token != Token::Eof {
            match self.current_token {
                Token::Keyword(ref k) if k == "meta" => {
                    meta = Some(self.parse_meta_block()?);
                }
                Token::Keyword(ref k) if k == "feature" => {
                    features.push(self.parse_feature_block()?);
                }
                Token::Keyword(ref k) if k == "deterministic" => {
                    deterministics.push(self.parse_deterministic_block()?);
                }
                Token::Keyword(ref k) if k == "sustainability" => {
                    sustainability.push(self.parse_sustainability_block()?);
                }
                _ => {
                    return Err(format!(
                        "Unexpected token {:?} in domain block at line {}, col {}",
                        self.current_token, self.lexer.line, self.lexer.column
                    ));
                }
            }
        }

        self.expect(Token::RBrace)?;

        let meta = meta.ok_or_else(|| "Missing meta block in domain".to_string())?;

        Ok(Domain {
            name,
            version,
            meta,
            features,
            deterministics,
            sustainability,
        })
    }

    fn parse_sustainability_block(&mut self) -> Result<SustainabilityBlock, String> {
        self.expect_keyword("sustainability")?;
        let domain_name = self.parse_string()?;
        let version = self.parse_string()?;
        self.expect(Token::LBrace)?;

        let mut mission = String::new();
        let mut sponsors = Vec::new();
        let mut roadmap = Vec::new();
        let mut license = String::new();

        while self.current_token != Token::RBrace && self.current_token != Token::Eof {
            let key = self.parse_ident()?;
            self.expect(Token::Colon)?;

            match key.as_str() {
                "mission" => mission = self.parse_string()?,
                "sponsors" => sponsors = self.parse_sponsors_array()?,
                "roadmap" => roadmap = self.parse_roadmap_array()?,
                "license" => license = self.parse_string()?,
                _ => {
                    return Err(format!(
                        "Unknown sustainability field '{}' at line {}, col {}",
                        key, self.lexer.line, self.lexer.column
                    ));
                }
            }

            if self.current_token == Token::Comma {
                self.advance()?;
            }
        }

        self.expect(Token::RBrace)?;

        Ok(SustainabilityBlock {
            domain_name,
            version,
            mission,
            sponsors,
            roadmap,
            license,
        })
    }

    fn parse_sponsors_array(&mut self) -> Result<Vec<Sponsor>, String> {
        self.expect(Token::LBracket)?;
        let mut sponsors = Vec::new();

        while self.current_token != Token::RBracket && self.current_token != Token::Eof {
            self.expect(Token::LBrace)?;
            let mut name = String::new();
            let mut sponsor_type = String::new();
            let mut amount = None;
            let mut period = String::new();
            let mut status = String::new();

            while self.current_token != Token::RBrace && self.current_token != Token::Eof {
                let key = self.parse_ident()?;
                self.expect(Token::Colon)?;

                match key.as_str() {
                    "name" => name = self.parse_string()?,
                    "type" => sponsor_type = self.parse_string()?,
                    "amount" => amount = Some(self.parse_number()?),
                    "period" => period = self.parse_string()?,
                    "status" => status = self.parse_string()?,
                    _ => {
                        return Err(format!(
                            "Unknown sponsor field '{}' at line {}, col {}",
                            key, self.lexer.line, self.lexer.column
                        ));
                    }
                }

                if self.current_token == Token::Comma {
                    self.advance()?;
                }
            }

            self.expect(Token::RBrace)?;
            sponsors.push(Sponsor {
                name,
                sponsor_type,
                amount,
                period,
                status,
            });

            if self.current_token == Token::Comma {
                self.advance()?;
            }
        }

        self.expect(Token::RBracket)?;
        Ok(sponsors)
    }

    fn parse_roadmap_array(&mut self) -> Result<Vec<Milestone>, String> {
        self.expect(Token::LBracket)?;
        let mut roadmap = Vec::new();

        while self.current_token != Token::RBracket && self.current_token != Token::Eof {
            self.expect(Token::LBrace)?;
            let mut milestone = String::new();
            let mut date = String::new();
            let mut funding_required = None;
            let mut revenue_target = None;

            while self.current_token != Token::RBrace && self.current_token != Token::Eof {
                let key = self.parse_ident()?;
                self.expect(Token::Colon)?;

                match key.as_str() {
                    "milestone" => milestone = self.parse_string()?,
                    "date" => date = self.parse_string()?,
                    "funding_required" => funding_required = Some(self.parse_number()?),
                    "revenue_target" => revenue_target = Some(self.parse_number()?),
                    _ => {
                        return Err(format!(
                            "Unknown milestone field '{}' at line {}, col {}",
                            key, self.lexer.line, self.lexer.column
                        ));
                    }
                }

                if self.current_token == Token::Comma {
                    self.advance()?;
                }
            }

            self.expect(Token::RBrace)?;
            roadmap.push(Milestone {
                milestone,
                date,
                funding_required,
                revenue_target,
            });

            if self.current_token == Token::Comma {
                self.advance()?;
            }
        }

        self.expect(Token::RBracket)?;
        Ok(roadmap)
    }

    fn parse_meta_block(&mut self) -> Result<MetaBlock, String> {
        self.expect_keyword("meta")?;
        self.expect(Token::At)?;
        self.expect(Token::LBrace)?;

        let mut name = String::new();
        let mut sprint_id = String::new();
        let mut author = String::new();
        let mut recipient = String::new();
        let mut baseline_centroid = String::new();
        let mut target_similarity = 0.0;
        let mut dimensions = 0;
        let mut note = None;

        while self.current_token != Token::RBrace && self.current_token != Token::Eof {
            let key = self.parse_ident()?;
            self.expect(Token::Colon)?;

            match key.as_str() {
                "name" => name = self.parse_string()?,
                "sprint_id" => sprint_id = self.parse_string()?,
                "author" => author = self.parse_string()?,
                "recipient" => recipient = self.parse_string()?,
                "baseline_centroid" => baseline_centroid = self.parse_string()?,
                "target_similarity" => target_similarity = self.parse_number()?,
                "dimensions" => dimensions = self.parse_number()? as u32,
                "note" => note = Some(self.parse_string()?),
                "description" | "concept" | "determinism_score" | "id" => {
                    // Ignore extra fields that might appear in meta block
                    match self.current_token {
                        Token::String(_) => { self.parse_string()?; }
                        Token::Number(_) => { self.parse_number()?; }
                        _ => { self.advance()?; }
                    }
                }
                _ => {
                    return Err(format!(
                        "Unknown meta field '{}' at line {}, col {}",
                        key, self.lexer.line, self.lexer.column
                    ));
                }
            }

            if self.current_token == Token::Comma {
                self.advance()?;
            }
        }

        self.expect(Token::RBrace)?;

        Ok(MetaBlock {
            name,
            sprint_id,
            author,
            recipient,
            baseline_centroid,
            target_similarity,
            dimensions,
            note,
        })
    }

    fn parse_feature_block(&mut self) -> Result<FeatureBlock, String> {
        self.expect_keyword("feature")?;
        let name = self.parse_string()?;
        self.expect(Token::LBrace)?;

        let mut weight = 1.0;
        let mut target = String::new();
        let mut description = String::new();
        let mut requirements = Vec::new();
        let mut dimension_contributions = BTreeMap::new();

        while self.current_token != Token::RBrace && self.current_token != Token::Eof {
            let key = self.parse_ident()?;
            self.expect(Token::Colon)?;

            match key.as_str() {
                "weight" => weight = self.parse_number()?,
                "target" => target = self.parse_string()?,
                "description" => description = self.parse_string()?,
                "requirements" => requirements = self.parse_string_array()?,
                "dimension_contributions" => dimension_contributions = self.parse_record()?,
                "intent" | "logic" | "parity_threshold" | "constraint" => {
                    // Ignore extra fields
                    match self.current_token {
                        Token::String(_) => { self.parse_string()?; }
                        Token::Number(_) => { self.parse_number()?; }
                        Token::LBracket => { self.parse_string_array()?; }
                        Token::LBrace => { self.parse_record()?; }
                        _ => { self.advance()?; }
                    }
                }
                _ => {
                    return Err(format!(
                        "Unknown feature field '{}' at line {}, col {}",
                        key, self.lexer.line, self.lexer.column
                    ));
                }
            }

            if self.current_token == Token::Comma {
                self.advance()?;
            }
        }

        self.expect(Token::RBrace)?;

        Ok(FeatureBlock {
            name,
            weight,
            target,
            description,
            requirements,
            dimension_contributions,
        })
    }

    fn parse_deterministic_block(&mut self) -> Result<DeterministicBlock, String> {
        self.expect_keyword("deterministic")?;
        let name = self.parse_string()?;
        self.expect(Token::LBrace)?;

        let mut input = Vec::new();
        let mut steps = Vec::new();
        let mut threshold = 0.0;

        while self.current_token != Token::RBrace && self.current_token != Token::Eof {
            let key = self.parse_ident()?;
            self.expect(Token::Colon)?;

            match key.as_str() {
                "input" => input = self.parse_string_array()?,
                "steps" => steps = self.parse_steps_array()?,
                "threshold" => threshold = self.parse_number()?,
                "success_condition" | "output" => {
                    // Ignore extra fields
                    match self.current_token {
                        Token::String(_) => { self.parse_string()?; }
                        Token::LBrace => {
                            self.expect(Token::LBrace)?;
                            while self.current_token != Token::RBrace && self.current_token != Token::Eof {
                                self.parse_ident()?;
                                self.expect(Token::Colon)?;
                                self.parse_string()?;
                                if self.current_token == Token::Comma {
                                    self.advance()?;
                                }
                            }
                            self.expect(Token::RBrace)?;
                        }
                        _ => { self.advance()?; }
                    }
                }
                _ => {
                    return Err(format!(
                        "Unknown deterministic field '{}' at line {}, col {}",
                        key, self.lexer.line, self.lexer.column
                    ));
                }
            }

            if self.current_token == Token::Comma {
                self.advance()?;
            }
        }

        self.expect(Token::RBrace)?;

        Ok(DeterministicBlock {
            name,
            input,
            steps,
            threshold,
        })
    }

    fn parse_string_array(&mut self) -> Result<Vec<String>, String> {
        self.expect(Token::LBracket)?;
        let mut arr = Vec::new();

        while self.current_token != Token::RBracket && self.current_token != Token::Eof {
            arr.push(self.parse_string()?);
            if self.current_token == Token::Comma {
                self.advance()?;
            }
        }

        self.expect(Token::RBracket)?;
        Ok(arr)
    }

    fn parse_record(&mut self) -> Result<BTreeMap<String, f64>, String> {
        self.expect(Token::LBrace)?;
        let mut map = BTreeMap::new();

        while self.current_token != Token::RBrace && self.current_token != Token::Eof {
            let key = self.parse_string()?;
            self.expect(Token::Colon)?;
            let val = self.parse_number()?;
            map.insert(key, val);

            if self.current_token == Token::Comma {
                self.advance()?;
            }
        }

        self.expect(Token::RBrace)?;
        Ok(map)
    }

    fn parse_steps_array(&mut self) -> Result<Vec<Step>, String> {
        self.expect(Token::LBracket)?;
        let mut steps = Vec::new();

        while self.current_token != Token::RBracket && self.current_token != Token::Eof {
            self.expect(Token::LBrace)?;
            let mut assert_val = None;
            let mut verify_val = None;

            while self.current_token != Token::RBrace && self.current_token != Token::Eof {
                let key = self.parse_ident()?;
                self.expect(Token::Colon)?;

                match key.as_str() {
                    "assert" => assert_val = Some(self.parse_string()?),
                    "verify" => verify_val = Some(self.parse_string()?),
                    "calculate" | "formula" | "evaluate" | "outcome" | "condition" => {
                        self.parse_string()?;
                    }
                    "conditions" => {
                        self.expect(Token::LBracket)?;
                        while self.current_token != Token::RBracket && self.current_token != Token::Eof {
                            self.expect(Token::LBrace)?;
                            while self.current_token != Token::RBrace && self.current_token != Token::Eof {
                                self.parse_ident()?;
                                self.expect(Token::Colon)?;
                                self.parse_string()?;
                                if self.current_token == Token::Comma {
                                    self.advance()?;
                                }
                            }
                            self.expect(Token::RBrace)?;
                            if self.current_token == Token::Comma {
                                self.advance()?;
                            }
                        }
                        self.expect(Token::RBracket)?;
                    }
                    _ => {
                        return Err(format!(
                            "Unknown step field '{}' at line {}, col {}",
                            key, self.lexer.line, self.lexer.column
                        ));
                    }
                }

                if self.current_token == Token::Comma {
                    self.advance()?;
                }
            }

            self.expect(Token::RBrace)?;
            steps.push(Step {
                assert: assert_val,
                verify: verify_val,
            });

            if self.current_token == Token::Comma {
                self.advance()?;
            }
        }

        self.expect(Token::RBracket)?;
        Ok(steps)
    }
}

import { Token, TokenType, GrammarViolationError } from './lexer';

export interface ASTDomain {
  name: string;
  version: string;
  meta: ASTMetaBlock;
  features: ASTFeatureBlock[];
  deterministics: ASTDeterministicBlock[];
  sustainability: ASTSustainabilityBlock[];
}

export interface ASTSustainabilityBlock {
  domain_name: string;
  version: string;
  mission: string;
  sponsors: ASTSponsor[];
  roadmap: ASTMilestone[];
  license: string;
}

export interface ASTSponsor {
  name: string;
  type: string;
  amount?: number;
  period: string;
  status: string;
}

export interface ASTMilestone {
  milestone: string;
  date: string;
  funding_required?: number;
  revenue_target?: number;
}

export interface ASTMetaBlock {
  name: string;
  sprint_id: string;
  author: string;
  recipient: string;
  baseline_centroid: string;
  target_similarity: number;
  dimensions: number;
}

export interface ASTFeatureBlock {
  name: string;
  weight: number;
  target: string;
  description: string;
  requirements: string[];
  dimension_contributions: Record<string, number>;
}

export interface ASTDeterministicBlock {
  name: string;
  input: string[];
  steps: ASTStep[];
  threshold: number;
}

export interface ASTStep {
  assert?: string;
  verify?: string;
}

export class Parser {
  private tokens: Token[];
  private position: number = 0;

  constructor(tokens: Token[]) {
    this.tokens = tokens;
  }

  private peek(): Token {
    if (this.position >= this.tokens.length) {
      return this.tokens[this.tokens.length - 1]; // EOF
    }
    return this.tokens[this.position];
  }

  private advance(): Token {
    const token = this.peek();
    this.position++;
    return token;
  }

  public parse(): ASTDomain {
    let hasContextualBrief = false;
    let hasScope = false;
    let hasAcceptanceCriteria = false;
    let hasFailsafeTest = false;

    while (this.peek().type !== 'EOF') {
      const token = this.advance();
      if (token.type === 'HEADING') {
        if (token.value.toLowerCase().includes('contextual brief')) {
          hasContextualBrief = true;
        } else if (token.value.toLowerCase().includes('scope')) {
          hasScope = true;
        } else if (token.value.toLowerCase().includes('acceptance criteria')) {
          hasAcceptanceCriteria = true;
        } else if (token.value.toLowerCase().includes('failsafe test')) {
          hasFailsafeTest = true;
        }
      }
    }

    if (!hasContextualBrief || !hasScope || !hasAcceptanceCriteria || !hasFailsafeTest) {
      throw new GrammarViolationError('Missing required section in Markdown TDB', 0, 0);
    }

    return {
      name: 'Markdown TDB',
      version: '8.2',
      meta: {
        name: 'Markdown TDB',
        sprint_id: 'MD-001',
        author: 'Markdown Parser',
        recipient: 'Tela AI',
        baseline_centroid: '',
        target_similarity: 1.0,
        dimensions: 1024
      },
      features: [
        {
          name: 'markdown_feature',
          weight: 1.0,
          target: 'markdown',
          description: 'Parsed from markdown',
          requirements: [],
          dimension_contributions: {
            'arch:determinism': 1.0
          }
        }
      ],
      deterministics: [],
      sustainability: []
    };
  }
}

// Core timeline module using rational arithmetic to avoid floating-point drift

#[repr(C)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct RationalTime {
    pub numerator: i64,
    pub denominator: i64,
}

impl RationalTime {
    pub fn new(numerator: i64, denominator: i64) -> Self {
        assert!(denominator != 0, "Denominator cannot be zero");
        Self { numerator, denominator }
    }

    pub fn add(self, other: Self) -> Self {
        let num = self.numerator * other.denominator + other.numerator * self.denominator;
        let den = self.denominator * other.denominator;
        Self::new(num, den)
    }
}

import { ASTDomain } from '../parser/parser';

export class RejectionBounceError extends Error {
  constructor(public similarity: number, public threshold: number) {
    super(`Rejection Bounce: Similarity ${similarity.toFixed(4)} is below threshold ${threshold.toFixed(4)}`);
    this.name = 'RejectionBounceError';
  }
}

// Mock FFI interface representing the WebAssembly bridge to the Rust Steel core
export interface OracleFFI {
  project_ast_to_vector(astJson: string): string; // returns JSON with vector and fingerprint
  calculate_parity(vectorA: Float64Array, vectorB: Float64Array): number;
}

export class VectorGuard {
  private oracle: OracleFFI;
  private activeTargetVector: Float64Array | null = null;
  private activeThreshold: number = 1.0;

  constructor(oracle: OracleFFI) {
    this.oracle = oracle;
  }

  public setActiveSprint(domain: ASTDomain, targetVector: Float64Array) {
    this.activeTargetVector = targetVector;
    this.activeThreshold = domain.meta.target_similarity;
  }

  /**
   * Hook into the file-save/commit lifecycle of Track A.
   * @param newAst The newly parsed AST from the proposed commit.
   * @returns true if the commit is allowed, throws RejectionBounceError otherwise.
   */
  public validateCommit(newAst: ASTDomain): boolean {
    if (!this.activeTargetVector) {
      throw new Error("No active sprint vector defined. Cannot validate commit.");
    }

    // 1. Beam new AST to the Oracle
    const astJson = JSON.stringify(newAst);
    const resultJson = this.oracle.project_ast_to_vector(astJson);
    const result = JSON.parse(resultJson);

    if (result.error) {
      throw new Error(`Oracle Error: ${result.error}`);
    }

    const newVector = new Float64Array(result.vector);

    // 2. Run it through calculate_parity
    const similarity = this.oracle.calculate_parity(this.activeTargetVector, newVector);

    // 3. Trigger Rejection Bounce if below threshold
    if (similarity < this.activeThreshold) {
      throw new RejectionBounceError(similarity, this.activeThreshold);
    }

    return true; // Commit allowed
  }
}

use std::hash::{Hash, Hasher};

/// A resolution scalar to convert continuous f32 positions to discrete integer ticks.
/// For example, 10000 ticks per unit to maintain high precision while allowing Eq/Hash.
pub const RESOLUTION_SCALAR: f32 = 10000.0;

#[derive(Debug, Clone, Copy)]
pub struct DiscretePosition {
    pub ticks: i32,
}

impl DiscretePosition {
    /// Maps a continuous f32 position to discrete integer ticks.
    pub fn from_f32(position: f32) -> Self {
        Self {
            ticks: (position * RESOLUTION_SCALAR).round() as i32,
        }
    }

    /// Converts the discrete ticks back to a continuous f32 position.
    pub fn to_f32(&self) -> f32 {
        self.ticks as f32 / RESOLUTION_SCALAR
    }
}

impl PartialEq for DiscretePosition {
    fn eq(&self, other: &Self) -> bool {
        self.ticks == other.ticks
    }
}

impl Eq for DiscretePosition {}

impl Hash for DiscretePosition {
    fn hash<H: Hasher>(&self, state: &mut H) {
        self.ticks.hash(state);
    }
}

/// A layout node that can be safely used in HashSets or HashMaps,
/// satisfying Rust's strict trait boundaries.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct LayoutNode {
    pub id: u64,
    pub x: DiscretePosition,
    pub y: DiscretePosition,
}

impl LayoutNode {
    pub fn new(id: u64, x: f32, y: f32) -> Self {
        Self {
            id,
            x: DiscretePosition::from_f32(x),
            y: DiscretePosition::from_f32(y),
        }
    }
}

